parameters.jsCode:
const items = $input.all();

// Loop semua item yang masuk
for (const item of items) {
  // Cek apakah ada data binary (biasanya bernama 'data')
  if (item.binary && item.binary.data) {
    // Kita paksa ubah label MIME type-nya agar dikenali Gemini
    // Karena sumber dari RapidAPI biasanya .m4a, kita pakai audio/mp4
    item.binary.data.mimeType = 'audio/mp4';
    item.binary.data.fileExtension = 'm4a';
    item.binary.data.fileName = 'audio_downloaded.m4a';
  }
}

return items;

// 1. Ambil data
const rawAi = $input.item.json.output || $input.item.json;
const ai = typeof rawAi === 'string' ? JSON.parse(rawAi) : rawAi;

// Fallback Metadata
const youtubeNode = $('YouTube - Fetch Video Details').first();
const youtubeData = youtubeNode ? youtubeNode.json : {};
const setNode = $('Set - Prepare Video Metadata').first();
const setData = setNode ? setNode.json : {};

const videoTitle = youtubeData.snippet?.title || setData.title || "Untitled";
const videoUrl = `https://www.youtube.com/watch?v=${youtubeData.id || setData.videoId}`;
const channelName = youtubeData.snippet?.channelTitle || setData.channelTitle || "Unknown";
const publishedAt = youtubeData.snippet?.publishedAt || setData.publishedAt || new Date().toISOString();
const thumbnailUrl = youtubeData.snippet?.thumbnails?.maxres?.url || youtubeData.snippet?.thumbnails?.high?.url || setData.thumbnailUrl;

// 2. ID DATABASE
const database_id = "PASTE_YOUR_NOTION_DATABASE_ID_HERE";

// 3. Properties Header
const properties = {
  "Name": { "title": [{ "text": { "content": videoTitle.substring(0, 2000) } }] },
  "URL": { "url": videoUrl },
  "Channel": { "select": { "name": channelName.replace(/,/g, '') } },
  "Topics": { "multi_select": (ai.key_topics || ["Learning"]).map(t => ({ "name": t })) },
  "Status": { "status": { "name": "🟢 Processed" } },
  "Summary": { "rich_text": [{ "text": { "content": ai.feynman_explanation || "-" } }] },
  "Published Date": { "date": { "start": publishedAt } },
  "Thumbnail": { "files": [{ "type": "external", "name": "Cover", "external": { "url": thumbnailUrl } }] }
};

// 4. Page Content (Active Learning Structure)
const children = [
  // --- Header Filosofi (FIXED ANNOTATIONS) ---
  {
    "object": "block",
    "type": "callout",
    "callout": {
      "rich_text": [{ 
        "text": { "content": "Active Learning Mode: Jangan cuma nonton. Konstruksi pengetahuanmu." },
        "annotations": { "italic": true } // Fixed: Annotations diluar text
      }],
      "icon": { "emoji": "🧠" },
      "color": "gray_background"
    }
  },

  // --- 1. TARGET (Micro-Goals) ---
  {
    "object": "block",
    "type": "heading_2",
    "heading_2": { "rich_text": [{ "text": { "content": "🎯 Preparation & Micro-Goals" } }] }
  },
  ...(ai.micro_goals || []).map(goal => ({
    "object": "block",
    "type": "to_do",
    "to_do": { "rich_text": [{ "text": { "content": goal } }], "checked": false }
  })),

  // --- 2. NOTES (Cornell Style) ---
  {
    "object": "block",
    "type": "heading_2",
    "heading_2": { "rich_text": [{ "text": { "content": "📝 Constructive Notes (Cornell)" } }] }
  },
  ...(ai.cornell_notes || []).map(note => ({
    "object": "block",
    "type": "toggle",
    "toggle": {
      "rich_text": [{ 
        "text": { "content": "❓ " + (note.trigger || "Pemicu") }, 
        "annotations": { "bold": true } 
      }],
      "children": [
        {
          "object": "block",
          "type": "paragraph",
          "paragraph": { "rich_text": [{ "text": { "content": "💡 " + (note.concept || "...") } }] }
        }
      ]
    }
  })),

  // --- 3. FEYNMAN TEST ---
  {
    "object": "block",
    "type": "heading_2",
    "heading_2": { "rich_text": [{ "text": { "content": "🗣️ The Feynman Test" } }] }
  },
  {
    "object": "block",
    "type": "quote",
    "quote": {
      "rich_text": [{ "text": { "content": ai.feynman_explanation || "Penjelasan tidak tersedia." } }],
      "color": "blue_background"
    }
  },
  {
    "object": "block",
    "type": "paragraph",
    "paragraph": { 
      "rich_text": [{ 
        "text": { "content": "Apakah penjelasan di atas sudah cukup sederhana? Bagian mana yang masih macet?" }, 
        "annotations": { "italic": true, "color": "gray" } 
      }] 
    }
  },

  // --- 4. IMMEDIATE EXECUTION (FIXED ANNOTATIONS) ---
  {
    "object": "block",
    "type": "heading_2",
    "heading_2": { "rich_text": [{ "text": { "content": "🛠️ Immediate Execution (The Lab)" } }] }
  },
  {
    "object": "block",
    "type": "callout",
    "callout": {
      "rich_text": [
        { 
          "text": { "content": "Tantangan Simulasi: " }, 
          "annotations": { "bold": true } // Fixed: Annotations diluar text
        },
        { "text": { "content": ai.simulation_task || "Coba terapkan konsep ini sekarang." } }
      ],
      "icon": { "emoji": "🧪" },
      "color": "red_background"
    }
  },
  {
    "object": "block",
    "type": "to_do",
    "to_do": { "rich_text": [{ "text": { "content": "Saya sudah mencoba tantangan di atas tanpa melihat tutorial." } }], "checked": false }
  }
];

return {
  json: {
    parent: { database_id: database_id },
    properties: properties,
    children: children
  }
};
